from flask import Flask
from flask_graphql import GraphQLView
import graphene
from graphene import ObjectType, String, Int, List, Field, Schema, DateTime
from datetime import datetime

# Mock data
products_data = [
    {"id": 1, "name": "Laptop", "price": 999.99, "category_id": 1, "description": "High performance laptop"},
    {"id": 2, "name": "Smartphone", "price": 599.99, "category_id": 2, "description": "Latest smartphone"},
    {"id": 3, "name": "Headphones", "price": 199.99, "category_id": 3, "description": "Wireless headphones"}
]

categories_data = [
    {"id": 1, "name": "Electronics"},
    {"id": 2, "name": "Mobile"},
    {"id": 3, "name": "Audio"}
]

reviews_data = [
    {"id": 1, "product_id": 1, "user": "Alice", "rating": 5, "comment": "Great laptop!", "created_at": "2023-01-01"},
    {"id": 2, "product_id": 1, "user": "Bob", "rating": 4, "comment": "Good performance", "created_at": "2023-01-02"},
    {"id": 3, "product_id": 2, "user": "Charlie", "rating": 5, "comment": "Amazing phone!", "created_at": "2023-01-03"}
]

class Review(ObjectType):
    id = Int()
    product_id = Int()
    user = String()
    rating = Int()
    comment = String()
    created_at = DateTime()

class Product(ObjectType):
    id = Int()
    name = String()
    price = Int()
    category_id = Int()
    description = String()
    reviews = List(Review)

class Category(ObjectType):
    id = Int()
    name = String()

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review)
    product_by_id = Field(Product, id=Int(required=True))
    category_by_id = Field(Category, id=Int(required=True))
    reviews_by_product = List(Review, product_id=Int(required=True))

    def resolve_products(self, info):
        return [Product(**product) for product in products_data]

    def resolve_categories(self, info):
        return [Category(**category) for category in categories_data]

    def resolve_reviews(self, info):
        return [Review(**review) for review in reviews_data]

    def resolve_product_by_id(self, info, id):
        product = next((p for p in products_data if p["id"] == id), None)
        return Product(**product) if product else None

    def resolve_category_by_id(self, info, id):
        category = next((c for c in categories_data if c["id"] == id), None)
        return Category(**category) if category else None

    def resolve_reviews_by_product(self, info, product_id):
        product_reviews = [r for r in reviews_data if r["product_id"] == product_id]
        return [Review(**review) for review in product_reviews]

schema = Schema(query=Query, types=[Product, Category, Review])

app = Flask(__name__)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True,
        introspection=True
    )
)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)